import { Search, Plus, Save, CheckCircle, AlertTriangle } from 'lucide-react';

interface Props {
  products: Product[];
  refreshData: () => void;
  reviewMode: boolean;
  onExitReviewMode?: () => void;
}

const MerchantView: React.FC<Props> = ({ products, refreshData, reviewMode, onExitReviewMode }) => {
