                  />
                  <button 
                    onClick={() => handleSavePrice(product)}
                    className="bg-emerald-600 text-white p-2 rounded-lg flex items-center justify-center gap-1 active:scale-95 transition-transform"
                  >
                    <Save className="w-4 h-4" /> حفظ
                  </button>
