    const productsToAdd: {name: string, price: string | null}[] = [];

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;

        // Regex Explanation:
        // ^(.*) -> Group 1: Capture everything from start (Name)
        // \s+   -> Match at least one space (Separator)
        // (\d+(?:,\d+)*)$ -> Group 2: Capture digits at the very end of the line (Price)
        // This ensures price is last thing on line and preceded by space.
        const match = trimmed.match(/^(.*)\s+(\d+(?:,\d+)*)$/);

        if (match) {
            const name = match[1].trim();
            const price = match[2];
            productsToAdd.push({ name, price });
