                        onClick={() => { setAddMode('bulk'); clearStatus(); }}
                        className={`flex-1 py-2 text-sm font-bold rounded-md transition-all ${addMode === 'bulk' ? 'bg-white shadow text-emerald-600' : 'text-slate-500 hover:text-slate-700'}`}
