import React, { useState, useEffect, useMemo } from 'react';
import { Product, CartItem, Order } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, Save, Copy, X, History, ChevronDown, Check, Edit2 } from 'lucide-react';
import { saveOrder, fetchOrders, deleteOrder, updateOrder } from '../services/productService';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  setCart: React.Dispatch<React.SetStateAction<CartItem[]>>;
}

const OrderSheet: React.FC<Props> = ({ isOpen, onClose, cart, setCart }) => {
  const [activeTab, setActiveTab] = useState<'current' | 'history'>('current');
  const [profitMargin, setProfitMargin] = useState(0); // Percentage
  const [savedOrders, setSavedOrders] = useState<Order[]>([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const [currentOrderId, setCurrentOrderId] = useState<string | null>(null); // If editing an existing order
  const [orderName, setOrderName] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  // Load history when tab changes
  useEffect(() => {
    if (activeTab === 'history') {
        setIsLoadingHistory(true);
        fetchOrders()
            .then(setSavedOrders)
            .catch(console.error)
            .finally(() => setIsLoadingHistory(false));
    }
  }, [activeTab]);

  const updateQuantity = (productId: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.productId === productId) {
              const newQty = Math.max(1, item.quantity + delta);
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const removeItem = (productId: string) => {
      setCart(prev => prev.filter(i => i.productId !== productId));
  };

  const totals = useMemo(() => {
      const baseTotal = cart.reduce((sum, item) => sum + (item.originalPrice * item.quantity), 0);
      const profitAmount = (baseTotal * profitMargin) / 100;
      const finalTotal = baseTotal + profitAmount;
      return { baseTotal, profitAmount, finalTotal };
  }, [cart, profitMargin]);

  const generateReceiptText = () => {
    const date = new Date().toLocaleDateString('ar-EG');
    let text = `🛒 *طلب جديد* (${orderName || date})\n`;
    text += `------------------\n`;

    cart.forEach((item, index) => {
        const itemTotal = item.originalPrice * item.quantity;
        // If profit is applied, show the effective unit price including profit
        const effectiveUnitPrice = item.originalPrice * (1 + profitMargin/100);
        const effectiveTotal = itemTotal * (1 + profitMargin/100);

        text += `${index + 1}. ${item.name} `;
        if(item.quantity > 1) text += `(عدد: ${item.quantity})`;
        text += `\n`;
        text += `   السعر: ${Math.round(effectiveTotal).toLocaleString()}\n`;
    });

    text += `------------------\n`;
    text += `💰 *الإجمالي: ${Math.round(totals.finalTotal).toLocaleString()} جنية*\n`;
    return text;
  };

  const handleCopy = () => {
      const text = generateReceiptText();
      navigator.clipboard.writeText(text);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleSave = async () => {
      if (cart.length === 0) return;

      const name = orderName || `طلب ${new Date().toLocaleDateString('ar-EG')} - ${new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'})}`;

      try {
          if (currentOrderId) {
              await updateOrder(currentOrderId, {
                  name,
                  items: cart,
                  profit_margin: profitMargin,
                  total_price: totals.finalTotal
              });
              alert("تم تحديث الطلب بنجاح");
          } else {
              await saveOrder({
                  name,
                  items: cart,
                  profit_margin: profitMargin,
                  total_price: totals.finalTotal
              });
              alert("تم حفظ الطلب الجديد");
          }
          // Reset or stay? Let's stay but refresh history logic could happen
          setOrderName('');
          setCurrentOrderId(null); // Clear editing ID so next save is new unless explicitly editing again
          setCart([]); // Clear cart
          onClose();
      } catch (e) {
          alert("فشل الحفظ");
          console.error(e);
      }
  };

  const loadOrderToCart = (order: Order) => {
      setCart(order.items);
      setProfitMargin(Number(order.profit_margin) || 0);
      setOrderName(order.name);
      setCurrentOrderId(order.id);
      setActiveTab('current');
  };

  const handleDeleteOrder = async (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
