import { supabase } from '../supabaseClient';
import { Product, Order, CartItem } from '../types';
import { parseInitialData } from '../constants';

const TABLE_NAME = 'products';
const ORDERS_TABLE = 'orders';

// Robust ID Generator (Polyfill for environments without secure crypto)
const generateId = (): string => {
    if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
        try {
            return crypto.randomUUID();
        } catch (e) {
            // Fallback if it fails
        }
    }
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
};

// Helper to sanitize price
const sanitizePrice = (price: number | string | null | undefined): number | null => {
    if (price === null || price === undefined) return null;
    if (typeof price === 'number') return price;
    if (typeof price === 'string') {
        if (price.trim() === '') return null;
        // Remove commas, keep dots for decimals if needed, but usually price is integer
        const cleanStr = price.replace(/,/g, '').trim();
        const num = Number(cleanStr);
        return isNaN(num) ? null : num;
    }
    return null;
};

// Check and seed data if empty
export const initializeData = async (): Promise<void> => {
  try {
    const { count, error } = await supabase
      .from(TABLE_NAME)
      .select('*', { count: 'exact', head: true });

    if (error) {
        console.error("Error checking DB:", error);
        return;
    }

    if (count === 0) {
      console.log("Database empty, seeding initial data...");
      const rawProducts = parseInitialData();

      const initialProducts = rawProducts.map(p => ({
          id: generateId(),
          ...p,
          price: sanitizePrice(p.price),
          last_updated: new Date().toISOString(),
          is_review_requested: false,
          review_batch_id: null
      }));

      const chunkSize = 50;
      for (let i = 0; i < initialProducts.length; i += chunkSize) {
        const chunk = initialProducts.slice(i, i + chunkSize);
        const { error: insertError } = await supabase.from(TABLE_NAME).insert(chunk);
        if (insertError) console.error("Seeding chunk error:", insertError);
      }
      console.log("Seeding complete.");
    }
  } catch (err) {
    console.error("Initialization error:", err);
  }
};

export const fetchProducts = async (): Promise<Product[]> => {
  // Add a timeout signal
  const { data, error } = await supabase
    .from(TABLE_NAME)
    .select('*')
    .order('name', { ascending: true })
    .abortSignal(AbortSignal.timeout(10000)); // 10s timeout

  if (error) throw error;
  return data as Product[];
};

export const updateProductPrice = async (id: string, price: number | string): Promise<void> => {
  const finalPrice = sanitizePrice(price);
  const { error } = await supabase
    .from(TABLE_NAME)
    .update({ 
        price: finalPrice, 
        last_updated: new Date().toISOString() 
    })
    .eq('id', id);

  if (error) throw error;
};

export const addProduct = async (name: string, price: number | string): Promise<Product | null> => {
    const finalPrice = sanitizePrice(price);

    const payload = { 
        id: generateId(),
        name: name.trim(), 
        price: finalPrice,
        is_review_requested: false,
        review_batch_id: null,
        last_updated: new Date().toISOString()
    };

    const { data, error } = await supabase
      .from(TABLE_NAME)
      .insert([payload])
      .select()
      .single();

    if (error) throw error;
    return data;
};

export const addBatchProducts = async (products: {name: string, price: number | string | null}[]): Promise<void> => {
    const finalProducts = products.map(p => ({
        id: generateId(),
        name: p.name.trim(),
        price: sanitizePrice(p.price),
        is_review_requested: false,
        review_batch_id: null,
        last_updated: new Date().toISOString()
    }));

    // Chunking
    const chunkSize = 50;
    for (let i = 0; i < finalProducts.length; i += chunkSize) {
        const chunk = finalProducts.slice(i, i + chunkSize);
        const { error } = await supabase.from(TABLE_NAME).insert(chunk);
        if (error) throw error;
    }
};

export const deleteProducts = async (ids: string[]): Promise<void> => {
    const { error } = await supabase
      .from(TABLE_NAME)
      .delete()
      .in('id', ids);

    if (error) throw error;
};

export const requestReview = async (productIds: string[], batchId: string): Promise<void> => {
    const { error } = await supabase
        .from(TABLE_NAME)
        .update({ 
            is_review_requested: true,
            review_batch_id: batchId
        })
        .in('id', productIds);

    if (error) throw error;
};

export const completeReview = async (productId: string): Promise<void> => {
    const { error } = await supabase
        .from(TABLE_NAME)
        .update({ 
            is_review_requested: false,
            review_batch_id: null
        })
        .eq('id', productId);

    if (error) throw error;
};

// --- Orders Logic ---

export const fetchOrders = async (): Promise<Order[]> => {
    const { data, error } = await supabase
      .from(ORDERS_TABLE)
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw error;
    return data as Order[];
};

export const saveOrder = async (order: {name: string, items: CartItem[], profit_margin: number, delivery_cost?: number, total_price: number}): Promise<Order | null> => {
    const { data, error } = await supabase
        .from(ORDERS_TABLE)
        .insert([{
            id: generateId(),
            ...order,
            created_at: new Date().toISOString()
        }])
        .select()
        .single();

    if (error) throw error;
    return data;
};

export const updateOrder = async (id: string, updates: Partial<Order>): Promise<void> => {
    const { error } = await supabase
        .from(ORDERS_TABLE)
        .update(updates)
        .eq('id', id);

    if (error) throw error;
};

export const deleteOrder = async (id: string): Promise<void> => {
    const { error } = await supabase
        .from(ORDERS_TABLE)
        .delete()
        .eq('id', id);

    if (error) throw error;
};

import React, { useState, useEffect, useRef } from 'react';
import { supabase } from './supabaseClient';
import { Product } from './types';
import { fetchProducts, initializeData } from './services/productService';
import MerchantView from './components/MerchantView';
import AdminPanel from './components/AdminPanel';
import { ShoppingBag, Lock, Bell, RefreshCw, Database, Copy, Check } from 'lucide-react';
import { FIX_SQL } from './constants';

const ADMIN_PIN = '0000'; // Simple PIN for demo

function App() {
  const [loading, setLoading] = useState(true);
  const [products, setProducts] = useState<Product[]>([]);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [headerClicks, setHeaderClicks] = useState(0);
  const [pin, setPin] = useState('');

  // Error handling state
  const [initError, setInitError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Ref for click timeout
  const clickTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const loadData = async () => {
    setLoading(true);
    setInitError(null);
    try {
      // Try to initialize/seed first (will fail gracefully usually, but good to run)
      await initializeData();

      const data = await fetchProducts();
      setProducts(data);
    } catch (error: any) {
      console.error(error);
      // Check for missing table error
      if (error.message?.includes('Could not find the table') || error.message?.includes('does not exist')) {
          setInitError('TABLE_MISSING');
      } else {
          setInitError(error.message || "حدث خطأ غير متوقع");
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();

    const subscription = supabase
      .channel('public:products')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, (payload) => {
        loadData();
      })
      .subscribe();

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const handleHeaderClick = () => {
    setHeaderClicks(prev => prev + 1);

    if (clickTimeoutRef.current) clearTimeout(clickTimeoutRef.current);

    clickTimeoutRef.current = setTimeout(() => {
      setHeaderClicks(0);
    }, 1000);

    if (headerClicks + 1 >= 3) {
      setShowLoginModal(true);
      setHeaderClicks(0);
    }
  };

  const handleLogin = () => {
    if (pin === ADMIN_PIN) {
      setIsAdmin(true);
      setShowLoginModal(false);
      setPin('');
    } else {
      alert("رمز خطأ");
      setPin('');
    }
  };

  const handleCopySQL = () => {
      navigator.clipboard.writeText(FIX_SQL);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
  };

  // 1. Render Error / Setup Screen
  if (initError === 'TABLE_MISSING') {
      return (
          <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4" dir="rtl">
              <div className="bg-white max-w-lg w-full rounded-2xl shadow-xl p-6 border-t-4 border-emerald-500">
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="bg-emerald-100 p-4 rounded-full mb-4">
                          <Database className="w-10 h-10 text-emerald-600" />
                      </div>
                      <h2 className="text-2xl font-bold text-slate-800">تجهيز قاعدة البيانات</h2>
                      <p className="text-slate-600 mt-2">
                          جدول المنتجات غير موجود. يرجى إنشاء الجدول في Supabase لتشغيل التطبيق.
                      </p>
                  </div>

                  <div className="bg-slate-900 rounded-lg p-4 mb-6 relative group">
                      <pre className="text-emerald-400 font-mono text-xs sm:text-sm overflow-x-auto whitespace-pre-wrap text-left dir-ltr h-40">
                          {FIX_SQL.trim()}
                      </pre>
                      <button 
                        onClick={handleCopySQL}
                        className="absolute top-2 right-2 bg-white/10 hover:bg-white/20 text-white p-2 rounded transition-colors"
                        title="نسخ الكود"
                      >
                          {copied ? <Check className="w-4 h-4 text-emerald-400" /> : <Copy className="w-4 h-4" />}
                      </button>
                  </div>

                  <div className="space-y-3">
                      <div className="text-sm text-slate-500 bg-slate-100 p-3 rounded-lg">
                          <ol className="list-decimal list-inside space-y-1">
                              <li>انسخ الكود أعلاه.</li>
                              <li>اذهب إلى لوحة تحكم <b>Supabase</b>.</li>
                              <li>افتح <b>SQL Editor</b> من القائمة الجانبية.</li>
                              <li>الصق الكود واضغط <b>Run</b>.</li>
                          </ol>
                      </div>
                      <button 
                        onClick={loadData}
                        className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 rounded-xl transition-colors flex items-center justify-center gap-2"
                      >
                          <RefreshCw className="w-5 h-5" />
                          تم التنفيذ، أعد المحاولة
                      </button>
                  </div>
              </div>
          </div>
      );
  }

  // 2. Render Loading
  if (loading && products.length === 0) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100 flex-col gap-4">
        <RefreshCw className="w-10 h-10 text-emerald-600 animate-spin" />
        <p className="text-gray-500 font-bold">جاري الاتصال بقاعدة البيانات...</p>
      </div>
    );
  }

  const pendingReviews = products.filter(p => p.is_review_requested).length;

  // 3. Render Admin Panel
  if (isAdmin) {
    return (
      <AdminPanel 
        products={products} 
        refreshData={loadData} 
        onLogout={() => setIsAdmin(false)} 
      />
    );
  }

  // 4. Render Merchant View (Main App)
  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      {/* Login Modal */}
      {showLoginModal && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl p-6 w-full max-w-xs animate-in zoom-in duration-200">
            <div className="text-center mb-6">
              <div className="bg-gray-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                <Lock className="w-8 h-8 text-gray-600" />
              </div>
              <h2 className="text-xl font-bold text-gray-800">الدخول للإدارة</h2>
            </div>
            <input 
              type="tel" 
              className="w-full text-center text-3xl font-bold tracking-widest p-3 border-2 border-gray-200 rounded-xl focus:border-emerald-500 outline-none mb-6"
              maxLength={4}
              value={pin}
              onChange={e => setPin(e.target.value)}
              placeholder="••••"
            />
            <button 
              onClick={handleLogin}
              className="w-full bg-slate-800 text-white py-3 rounded-xl font-bold shadow-lg active:scale-95 transition-transform"
            >
              دخول
            </button>
            <button 
              onClick={() => setShowLoginModal(false)}
              className="w-full mt-3 text-gray-500 py-2"
            >
              إلغاء
            </button>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-emerald-600 text-white pt-safe pb-4 px-4 shadow-lg rounded-b-[2rem]">
        <div className="flex justify-between items-center mt-2">
           <div 
             onClick={handleHeaderClick} 
             className="flex items-center gap-2 select-none cursor-pointer active:opacity-50 transition-opacity"
           >
             <div className="bg-white/20 p-2 rounded-lg backdrop-blur-sm">
               <ShoppingBag className="w-6 h-6 text-white" />
             </div>
             <div>
               <h1 className="font-bold text-lg">السوق السوداني</h1>
               <p className="text-emerald-100 text-xs">قائمة الأسعار</p>
             </div>
           </div>

           {pendingReviews > 0 && (
               <div className="bg-orange-500 text-white px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1 animate-bounce">
                   <Bell className="w-3 h-3" />
                   {pendingReviews} طلب مراجعة
               </div>
           )}
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-md mx-auto">
        <MerchantView 
            products={products} 
            refreshData={loadData}
            reviewMode={pendingReviews > 0} 
            isAdmin={isAdmin} 
        />
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { Product, CartItem } from '../types';
import { updateProductPrice, addProduct, completeReview } from '../services/productService';
import { Search, Plus, Save, CheckCircle, AlertTriangle, AlertCircle, ShoppingCart } from 'lucide-react';
import OrderSheet from './OrderSheet';

interface Props {
  products: Product[];
  refreshData: () => void;
  reviewMode: boolean;
  onExitReviewMode?: () => void;
  isAdmin?: boolean; // Add prop to check if user is admin
}

const MerchantView: React.FC<Props> = ({ products, refreshData, reviewMode, onExitReviewMode, isAdmin = false }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Cart State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isOrderSheetOpen, setIsOrderSheetOpen] = useState(false);

  // New Product State
  const [newName, setNewName] = useState('');
  const [newPrice, setNewPrice] = useState('');

  // Filter products
  const filteredProducts = products.filter(p => {
      const matchesSearch = p.name.includes(searchTerm);
      if (reviewMode) {
          return p.is_review_requested && matchesSearch;
      }
      return matchesSearch;
  });

  const handleEditClick = (p: Product) => {
    setEditingId(p.id);
    setTempPrice(p.price !== null && p.price !== undefined ? p.price.toString() : '');
  };

  const handleSavePrice = async (p: Product) => {
    try {
      await updateProductPrice(p.id, tempPrice);

      // If in review mode, mark as complete automatically when saved
      if (p.is_review_requested) {
          await completeReview(p.id);
      }

      setEditingId(null);
      refreshData();
    } catch (e: any) {
      console.error(e);
      alert("حدث خطأ أثناء الحفظ: " + (e.message || "خطأ غير معروف"));
    }
  };

  const handleMarkReviewed = async (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      try {
          await completeReview(id);
          refreshData();
      } catch (e) {
          alert("خطأ في الشبكة");
      }
  };

  const addToCart = (p: Product, e: React.MouseEvent) => {
      e.stopPropagation();
      if (p.price === null) {
          alert("لا يمكن إضافة منتج غير مسعر. يرجى تسعيره أولاً.");
          return;
      }

      setCart(prev => {
          const existing = prev.find(item => item.productId === p.id);
          if (existing) {
              return prev.map(item => item.productId === p.id ? { ...item, quantity: item.quantity + 1 } : item);
          }
          return [...prev, {
              productId: p.id,
              name: p.name,
              originalPrice: Number(p.price),
              quantity: 1
          }];
      });
      // Optional: Give feedback
  };

  const handleAddNew = async () => {
      if (!newName) return;
      setIsSubmitting(true);
      setErrorMsg(null);
      try {
          await addProduct(newName, newPrice);
          setNewName('');
          setNewPrice('');
          setIsAddModalOpen(false);
          refreshData();
      } catch (e: any) {
          console.error(e);
          setErrorMsg("فشل الإضافة: " + (e.message || "خطأ في الشبكة"));
      } finally {
          setIsSubmitting(false);
      }
  };

  return (
    <div className="pb-24">
      {/* Order Sheet Modal - Only active if Admin */}
      {isAdmin && (
          <OrderSheet 
            isOpen={isOrderSheetOpen} 
            onClose={() => setIsOrderSheetOpen(false)} 
            cart={cart}
            setCart={setCart}
          />
      )}

      {/* Review Mode Banner */}
      {reviewMode && (
          <div className="bg-orange-100 border-b-2 border-orange-400 p-4 sticky top-16 z-20 flex justify-between items-center shadow-md">
              <div className="flex items-center gap-2 text-orange-800">
                  <AlertTriangle className="w-6 h-6 animate-pulse" />
                  <span className="font-bold text-lg">مطلوب مراجعة الأسعار ({filteredProducts.length})</span>
              </div>
              {onExitReviewMode && (
                  <button onClick={onExitReviewMode} className="text-sm bg-white px-3 py-1 rounded border border-orange-300">
                      إلغاء
                  </button>
              )}
          </div>
      )}

      {/* Search Bar */}
      <div className="sticky top-0 z-10 bg-gray-100 p-4 shadow-sm flex gap-2">
        <div className="relative flex-1">
          <input
            type="text"
            placeholder="بحث عن منتج..."
            className="w-full pl-4 pr-10 py-3 rounded-xl border border-gray-300 focus:outline-none focus:ring-2 focus:ring-emerald-500 text-lg shadow-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <Search className="absolute right-3 top-3.5 text-gray-400 w-6 h-6" />
        </div>
        {/* Only show Cart button if Admin */}
        {!reviewMode && isAdmin && (
            <button 
                onClick={() => setIsOrderSheetOpen(true)}
                className="bg-slate-800 text-white px-4 rounded-xl flex items-center justify-center relative shadow-sm"
            >
                <ShoppingCart className="w-6 h-6" />
                {cart.length > 0 && (
                    <span className="absolute -top-2 -right-2 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold border-2 border-gray-100">
                        {cart.length}
                    </span>
                )}
            </button>
        )}
      </div>

      {/* Product List */}
      <div className="p-4 space-y-3">
        {filteredProducts.map((product) => (
          <div 
            key={product.id} 
            className={`bg-white rounded-xl shadow-sm border p-4 transition-all duration-200 ${product.is_review_requested ? 'border-orange-400 ring-1 ring-orange-200 bg-orange-50' : 'border-gray-100'}`}
          >
            <div className="flex justify-between items-start gap-3">
              <div className="flex-1" onClick={() => handleEditClick(product)}>
                <h3 className="font-bold text-gray-800 text-lg leading-snug mb-1">{product.name}</h3>
                {product.is_review_requested && (
                    <span className="inline-block bg-orange-200 text-orange-800 text-xs px-2 py-0.5 rounded-full mb-2">مراجعة مطلوبة</span>
                )}
              </div>

              {editingId === product.id ? (
                <div className="flex flex-col gap-2 w-32 animate-in fade-in slide-in-from-right-4 duration-300">
                  <input
                    type="number"
                    className="w-full p-2 border-2 border-emerald-500 rounded-lg text-center text-lg font-bold bg-white"
                    value={tempPrice}
                    onChange={(e) => setTempPrice(e.target.value)}
                    autoFocus
                  />
                  <button 
                    onClick={() => handleSavePrice(product)}
                    className="bg-emerald-600 text-white p-2 rounded-lg flex items-center justify-center gap-1 active:scale-95 transition-transform"
                  >
                    <Save className="w-4 h-4" /> حفظ
                  </button>
                </div>
              ) : (
                <div 
                    onClick={() => handleEditClick(product)}
                    className="flex flex-col items-end min-w-[80px]"
                >
                  <span className={`text-xl font-bold ${product.price !== null ? 'text-emerald-700' : 'text-gray-400'}`}>
                    {product.price !== null ? Number(product.price).toLocaleString() : '---'}
                  </span>
                  <span className="text-xs text-gray-500 mb-2">جنية</span>

                  {reviewMode && product.is_review_requested ? (
                      <button 
                        onClick={(e) => handleMarkReviewed(product.id, e)}
                        className="mt-1 bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full text-xs font-bold border border-emerald-200 flex items-center gap-1"
                      >
                          <CheckCircle className="w-3 h-3" /> تم
                      </button>
                  ) : (
                      /* Only show Add to Cart if Admin */
                      !reviewMode && isAdmin && product.price !== null && (
                          <button 
                            onClick={(e) => addToCart(product, e)}
                            className="bg-gray-100 hover:bg-emerald-100 text-gray-600 hover:text-emerald-700 p-2 rounded-full transition-colors"
                          >
                              <Plus className="w-5 h-5" />
                          </button>
                      )
                  )}
                </div>
              )}
            </div>
          </div>
        ))}

        {filteredProducts.length === 0 && (
            <div className="text-center py-10 text-gray-400">
                <p>لا توجد منتجات مطابقة</p>
            </div>
        )}
      </div>

      {/* Add Button (Floating) - Only if Admin */}
      {!reviewMode && isAdmin && (
          <button 
            onClick={() => { setIsAddModalOpen(true); setErrorMsg(null); }}
            className="fixed left-6 bottom-6 bg-emerald-600 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center active:scale-90 transition-transform z-30"
          >
            <Plus className="w-8 h-8" />
          </button>
      )}

      {/* Add Modal */}
      {isAddModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-end sm:items-center justify-center">
          <div className="bg-white w-full sm:w-96 rounded-t-2xl sm:rounded-2xl p-6 shadow-2xl animate-in slide-in-from-bottom duration-300">
            <h2 className="text-xl font-bold mb-4 text-emerald-800">إضافة سلعة جديدة</h2>

            {errorMsg && (
                <div className="bg-red-50 text-red-600 p-3 rounded-lg mb-4 text-sm flex items-center gap-2">
                    <AlertCircle className="w-4 h-4" />
                    {errorMsg}
                </div>
            )}

            <div className="space-y-4">
              <div>
                <label className="block text-sm text-gray-600 mb-1">اسم المنتج</label>
                <input 
                  type="text" 
                  value={newName} 
                  onChange={e => setNewName(e.target.value)}
                  className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  placeholder="مثال: سكر 10 كيلو"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-600 mb-1">السعر (اختياري)</label>
                <input 
                  type="number" 
                  value={newPrice} 
                  onChange={e => setNewPrice(e.target.value)}
                  className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  placeholder="0"
                />
              </div>

              <div className="flex gap-3 mt-6">
                <button 
                    onClick={handleAddNew}
                    disabled={isSubmitting}
                    className="flex-1 bg-emerald-600 text-white py-3 rounded-xl font-bold disabled:opacity-50"
                >
                    {isSubmitting ? 'جاري الإضافة...' : 'إضافة'}
                </button>
                <button 
                    onClick={() => setIsAddModalOpen(false)}
                    className="flex-1 bg-gray-200 text-gray-700 py-3 rounded-xl font-bold"
                >
                    إلغاء
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default MerchantView;

import React, { useState, useEffect, useMemo } from 'react';
import { Product, CartItem, Order } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, Save, Copy, X, History, ChevronDown, Check, Edit2, Truck, Percent } from 'lucide-react';
import { saveOrder, fetchOrders, deleteOrder, updateOrder } from '../services/productService';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  setCart: React.Dispatch<React.SetStateAction<CartItem[]>>;
}

const OrderSheet: React.FC<Props> = ({ isOpen, onClose, cart, setCart }) => {
  const [activeTab, setActiveTab] = useState<'current' | 'history'>('current');
  const [globalProfitMargin, setGlobalProfitMargin] = useState(0); // Percentage
  const [deliveryCost, setDeliveryCost] = useState<string>(''); // Kept as string for input handling
  const [savedOrders, setSavedOrders] = useState<Order[]>([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const [currentOrderId, setCurrentOrderId] = useState<string | null>(null); // If editing an existing order
  const [orderName, setOrderName] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  // Load history when tab changes
  useEffect(() => {
    if (activeTab === 'history') {
        setIsLoadingHistory(true);
        fetchOrders()
            .then(setSavedOrders)
            .catch(console.error)
            .finally(() => setIsLoadingHistory(false));
    }
  }, [activeTab]);

  const updateQuantity = (productId: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.productId === productId) {
              const newQty = Math.max(1, item.quantity + delta);
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const updateItemProfit = (productId: string, profit: number) => {
      setCart(prev => prev.map(item => {
          if (item.productId === productId) {
              return { ...item, itemProfit: profit };
          }
          return item;
      }));
  };

  const removeItem = (productId: string) => {
      setCart(prev => prev.filter(i => i.productId !== productId));
  };

  // Calculations
  const totals = useMemo(() => {
      let subTotal = 0;

      cart.forEach(item => {
          // Use item specific profit if set, otherwise global
          const margin = item.itemProfit !== undefined ? item.itemProfit : globalProfitMargin;
          const unitPriceWithProfit = item.originalPrice * (1 + margin / 100);
          subTotal += unitPriceWithProfit * item.quantity;
      });

      const delivery = Number(deliveryCost) || 0;
      const grandTotal = subTotal + delivery;

      return { subTotal, delivery, grandTotal };
  }, [cart, globalProfitMargin, deliveryCost]);

  const generateReceiptText = () => {
    // Determine Order Name/ID
    const title = orderName || 'بدون رقم';

    let text = `✅ تم استلام طلبك\n`;
    text += `رقم الطلب: ${title}\n\n`;
    text += `المنتجات:\n`;

    cart.forEach((item) => {
        const margin = item.itemProfit !== undefined ? item.itemProfit : globalProfitMargin;
        const unitPriceWithProfit = item.originalPrice * (1 + margin / 100);
        const itemTotal = unitPriceWithProfit * item.quantity;

        text += `${item.name} × ${item.quantity} = ${Math.round(itemTotal).toLocaleString()}\n`;
    });

    text += `\n💰 الإجمالي: ${Math.round(totals.subTotal).toLocaleString()} جنيه\n`;

    if (totals.delivery > 0) {
        text += `🚚 التوصيل: ${Math.round(totals.delivery).toLocaleString()} جنيه\n`;
    }

    text += `الاجمالي الكلي: ${Math.round(totals.grandTotal).toLocaleString()} جنية\n`;
    text += `📦 التسليم اليوم مساءً إن شاء الله\n\n`;
    text += `شكرًا لثقتك 🌸`;
    return text;
  };

  const handleCopy = () => {
      const text = generateReceiptText();
      navigator.clipboard.writeText(text);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleSave = async () => {
      if (cart.length === 0) return;

      const name = orderName || `طلب ${new Date().toLocaleDateString('ar-EG')} - ${new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'})}`;

      try {
          const orderData = {
              name,
              items: cart,
              profit_margin: globalProfitMargin,
              delivery_cost: Number(deliveryCost) || 0,
              total_price: totals.grandTotal
          };

          if (currentOrderId) {
              await updateOrder(currentOrderId, orderData);
              alert("تم تحديث الطلب بنجاح");
          } else {
              await saveOrder(orderData);
              alert("تم حفظ الطلب الجديد");
          }

          setOrderName('');
          setDeliveryCost('');
          setCurrentOrderId(null);
          setCart([]);
          onClose();
      } catch (e) {
          alert("فشل الحفظ");
          console.error(e);
      }
  };

  const loadOrderToCart = (order: Order) => {
      setCart(order.items);
      setGlobalProfitMargin(Number(order.profit_margin) || 0);
      setDeliveryCost(order.delivery_cost?.toString() || '');
      setOrderName(order.name);
      setCurrentOrderId(order.id);
      setActiveTab('current');
  };

  const handleDeleteOrder = async (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      if(!window.confirm("حذف هذا السجل؟")) return;
      try {
          await deleteOrder(id);
          setSavedOrders(prev => prev.filter(o => o.id !== id));
      } catch (e) {
          alert("فشل الحذف");
      }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/30 backdrop-blur-sm" onClick={onClose} />

      {/* Sliding Panel */}
      <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">

        {/* Header */}
        <div className="p-4 bg-slate-800 text-white flex justify-between items-center shadow-md z-10">
            <h2 className="text-xl font-bold flex items-center gap-2">
                <ShoppingCart className="w-6 h-6 text-emerald-400" />
                إدارة الطلبات (Admin)
            </h2>
            <button onClick={onClose} className="p-2 hover:bg-slate-700 rounded-full">
                <X className="w-6 h-6" />
            </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b">
            <button 
                onClick={() => setActiveTab('current')}
                className={`flex-1 py-3 font-bold text-sm flex items-center justify-center gap-2 transition-colors ${activeTab === 'current' ? 'text-emerald-600 border-b-2 border-emerald-600 bg-emerald-50' : 'text-gray-500'}`}
            >
                <Edit2 className="w-4 h-4" />
                الطلب الحالي ({cart.length})
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`flex-1 py-3 font-bold text-sm flex items-center justify-center gap-2 transition-colors ${activeTab === 'history' ? 'text-emerald-600 border-b-2 border-emerald-600 bg-emerald-50' : 'text-gray-500'}`}
            >
                <History className="w-4 h-4" />
                السجل المحفوظ
            </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto bg-gray-50 p-4">
            {activeTab === 'current' && (
                <>
                    {cart.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-gray-400">
                            <ShoppingCart className="w-16 h-16 mb-4 opacity-20" />
                            <p>السلة فارغة</p>
                            <p className="text-sm">أضف منتجات من القائمة الرئيسية</p>
                        </div>
                    ) : (
                        <div className="space-y-4 pb-20">
                            {/* Order Name */}
                            <input 
                                className="w-full p-2 border rounded-lg mb-2 text-sm"
                                placeholder="اسم الطلب / رقم الطلب"
                                value={orderName}
                                onChange={e => setOrderName(e.target.value)}
                            />

                            {/* Items List */}
                            <div className="space-y-3">
                                {cart.map(item => {
                                    const itemMargin = item.itemProfit !== undefined ? item.itemProfit : globalProfitMargin;
                                    const effectivePrice = item.originalPrice * (1 + itemMargin / 100);

                                    return (
                                        <div key={item.productId} className="bg-white p-3 rounded-lg shadow-sm border border-gray-200">
                                            <div className="flex justify-between items-start mb-2">
                                                <span className="font-bold text-gray-800">{item.name}</span>
                                                <button onClick={() => removeItem(item.productId)} className="text-red-400 hover:text-red-600">
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            </div>

                                            <div className="flex justify-between items-center mb-2">
                                                <div className="text-sm text-gray-500">
                                                    الأساسي: {item.originalPrice.toLocaleString()}
                                                </div>
                                                <div className="flex items-center gap-1 text-xs bg-slate-100 px-2 py-1 rounded">
                                                     <Percent className="w-3 h-3 text-slate-500"/>
                                                     <input 
                                                        type="number"
                                                        className="w-8 bg-transparent text-center border-b border-slate-300 focus:border-emerald-500 outline-none"
                                                        value={item.itemProfit !== undefined ? item.itemProfit : ''}
                                                        placeholder={globalProfitMargin.toString()}
                                                        onChange={(e) => updateItemProfit(item.productId, Number(e.target.value))}
                                                     />
                                                     <span>%</span>
                                                </div>
                                            </div>

                                            <div className="flex justify-between items-center border-t pt-2">
                                                <div className="font-bold text-emerald-700">
                                                    {Math.round(effectivePrice * item.quantity).toLocaleString()} جنية
                                                </div>
                                                <div className="flex items-center gap-3 bg-gray-100 rounded-lg px-2 py-1">
                                                    <button onClick={() => updateQuantity(item.productId, -1)} className="p-1 hover:bg-white rounded shadow-sm"><Minus className="w-3 h-3"/></button>
                                                    <span className="font-bold w-4 text-center">{item.quantity}</span>
                                                    <button onClick={() => updateQuantity(item.productId, 1)} className="p-1 hover:bg-white rounded shadow-sm"><Plus className="w-3 h-3"/></button>
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Global Settings */}
                            <div className="bg-white p-4 rounded-lg shadow-sm mt-4 border border-slate-200 space-y-4">
                                <div>
                                    <label className="block text-sm font-bold text-gray-700 mb-2">نسبة الربح العامة (%)</label>
                                    <div className="flex gap-4 items-center">
                                        <input 
                                            type="range" min="0" max="100" step="1"
                                            value={globalProfitMargin}
                                            onChange={e => setGlobalProfitMargin(Number(e.target.value))}
                                            className="flex-1 accent-emerald-600"
                                        />
                                        <span className="bg-emerald-100 text-emerald-800 px-3 py-1 rounded-lg font-bold min-w-[3rem] text-center">
                                            {globalProfitMargin}%
                                        </span>
                                    </div>
                                    <p className="text-xs text-gray-400 mt-1">يتم تطبيقها على المنتجات التي لم تحدد لها نسبة خاصة</p>
                                </div>

                                <div className="border-t pt-3">
                                     <label className="block text-sm font-bold text-gray-700 mb-2 flex items-center gap-2">
                                        <Truck className="w-4 h-4"/>
                                        تكلفة التوصيل
                                     </label>
                                     <input 
                                        type="number"
                                        className="w-full p-2 border rounded-lg"
                                        placeholder="0"
                                        value={deliveryCost}
                                        onChange={e => setDeliveryCost(e.target.value)}
                                     />
                                </div>
                            </div>
                        </div>
                    )}
                </>
            )}

            {activeTab === 'history' && (
                <div className="space-y-3">
                    {isLoadingHistory ? (
                        <p className="text-center text-gray-500 mt-10">جاري التحميل...</p>
                    ) : savedOrders.length === 0 ? (
                        <p className="text-center text-gray-400 mt-10">لا توجد طلبات محفوظة</p>
                    ) : (
                        savedOrders.map(order => (
                            <div key={order.id} onClick={() => loadOrderToCart(order)} className="bg-white p-3 rounded-lg shadow-sm border hover:border-emerald-400 cursor-pointer transition-colors group relative">
                                <div className="font-bold text-gray-800 mb-1">{order.name || 'بدون اسم'}</div>
                                <div className="text-xs text-gray-500 mb-2">
                                    {new Date(order.created_at).toLocaleDateString('ar-EG')} • {order.items.length} منتج
                                </div>
                                <div className="flex justify-between items-center">
                                    <div className="font-bold text-emerald-600">
                                        {Number(order.total_price).toLocaleString()} جنية
                                    </div>
                                    {order.delivery_cost && order.delivery_cost > 0 && (
                                        <span className="text-xs bg-slate-100 px-2 py-1 rounded flex items-center gap-1">
                                            <Truck className="w-3 h-3"/> {order.delivery_cost}
                                        </span>
                                    )}
                                </div>
                                <button 
                                    onClick={(e) => handleDeleteOrder(order.id, e)}
                                    className="absolute top-3 left-3 text-red-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                            </div>
                        ))
                    )}
                </div>
            )}
        </div>

        {/* Footer Actions (Only for Current Tab) */}
        {activeTab === 'current' && cart.length > 0 && (
            <div className="p-4 bg-white border-t shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                <div className="space-y-1 mb-4">
                    <div className="flex justify-between text-sm text-gray-600">
                        <span>المجموع:</span>
                        <span>{Math.round(totals.subTotal).toLocaleString()}</span>
                    </div>
                    {totals.delivery > 0 && (
                        <div className="flex justify-between text-sm text-gray-600">
                            <span>التوصيل:</span>
                            <span>{Math.round(totals.delivery).toLocaleString()}</span>
                        </div>
                    )}
                    <div className="flex justify-between font-bold text-xl text-slate-900 border-t pt-2 mt-2">
                        <span>الإجمالي الكلي:</span>
                        <span>{Math.round(totals.grandTotal).toLocaleString()}</span>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <button 
                        onClick={handleCopy}
                        className="flex items-center justify-center gap-2 bg-slate-100 text-slate-700 py-3 rounded-xl font-bold hover:bg-slate-200 transition-colors"
                    >
                        {copySuccess ? <Check className="w-5 h-5 text-green-600" /> : <Copy className="w-5 h-5" />}
                        {copySuccess ? 'تم النسخ' : 'نسخ الطلب'}
                    </button>
                    <button 
                        onClick={handleSave}
                        className="flex items-center justify-center gap-2 bg-slate-800 text-white py-3 rounded-xl font-bold hover:bg-slate-700 transition-colors"
                    >
                        <Save className="w-5 h-5" />
                        {currentOrderId ? 'تحديث' : 'حفظ'}
                    </button>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

export default OrderSheet;

import React, { useState } from 'react';
import { Product, CartItem } from '../types';
import { requestReview, addProduct, addBatchProducts, deleteProducts } from '../services/productService';
import { exportToExcel } from '../utils/excelExport';
import { Download, Send, CheckSquare, Square, Search, X, LogOut, PackagePlus, FileText, ListPlus, AlertCircle, CheckCircle, Trash2, Database, Copy, Check, ShoppingCart, Plus } from 'lucide-react';
import { FIX_SQL } from '../constants';
import OrderSheet from './OrderSheet';

interface Props {
  products: Product[];
  refreshData: () => void;
  onLogout: () => void;
}

const AdminPanel: React.FC<Props> = ({ products, refreshData, onLogout }) => {
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');
  const [sending, setSending] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [activeTab, setActiveTab] = useState<'manage' | 'add'>('manage');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Cart State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isOrderSheetOpen, setIsOrderSheetOpen] = useState(false);

  // SQL Help Modal
  const [showSqlHelp, setShowSqlHelp] = useState(false);
  const [copied, setCopied] = useState(false);

  // Feedback Status
  const [statusMsg, setStatusMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);

  // Add Product State
  const [addMode, setAddMode] = useState<'single' | 'bulk'>('single');
  const [newProductName, setNewProductName] = useState('');
  const [newProductPrice, setNewProductPrice] = useState('');
  const [bulkText, setBulkText] = useState('');

  const filteredProducts = products.filter(p => p.name.includes(searchTerm));

  const toggleSelect = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedIds(newSet);
  };

  const selectAll = () => {
      if (selectedIds.size === filteredProducts.length) {
          setSelectedIds(new Set());
      } else {
          setSelectedIds(new Set(filteredProducts.map(p => p.id)));
      }
  };

  const clearStatus = () => setStatusMsg(null);

  const handleCopySQL = () => {
      navigator.clipboard.writeText(FIX_SQL);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
  };

  const addToCart = (p: Product, e: React.MouseEvent) => {
      e.stopPropagation();
      if (p.price === null) {
          alert("لا يمكن إضافة منتج غير مسعر.");
          return;
      }

      setCart(prev => {
          const existing = prev.find(item => item.productId === p.id);
          if (existing) {
              return prev.map(item => item.productId === p.id ? { ...item, quantity: item.quantity + 1 } : item);
          }
          return [...prev, {
              productId: p.id,
              name: p.name,
              originalPrice: Number(p.price),
              quantity: 1
          }];
      });
      setStatusMsg({type: 'success', text: "تمت الإضافة للسلة"});
      setTimeout(clearStatus, 1500);
  };

  const handleSendReview = async () => {
    if (selectedIds.size === 0) return;
    setSending(true);
    clearStatus();
    try {
      const batchId = `BATCH-${Math.floor(Math.random() * 10000)}`;
      await requestReview(Array.from(selectedIds), batchId);
      setStatusMsg({type: 'success', text: "تم إرسال طلب المراجعة بنجاح"});
      setSelectedIds(new Set());
      refreshData();
    } catch (e: any) {
      setStatusMsg({type: 'error', text: "فشل الإرسال: " + (e.message || "خطأ غير معروف")});
    } finally {
      setSending(false);
    }
  };

  const handleBulkDelete = async () => {
      if (selectedIds.size === 0) return;

      const confirmMsg = `هل أنت متأكد من حذف ${selectedIds.size} منتج؟ لا يمكن التراجع عن هذا الإجراء.`;
      if (!window.confirm(confirmMsg)) return;

      setIsDeleting(true);
      clearStatus();
      try {
          await deleteProducts(Array.from(selectedIds));
          setStatusMsg({type: 'success', text: "تم الحذف بنجاح"});
          setSelectedIds(new Set());
          refreshData();
      } catch (e: any) {
          console.error(e);
          const errorText = e.message || "خطأ غير معروف";
          setStatusMsg({type: 'error', text: `فشل الحذف (${errorText}). يرجى التحقق من إعدادات قاعدة البيانات.`});
      } finally {
          setIsDeleting(false);
      }
  };

  const handleSingleDelete = async (id: string) => {
      if (!window.confirm("هل أنت متأكد من حذف هذا المنتج نهائياً؟")) return;

      setIsDeleting(true);
      clearStatus();
      try {
          await deleteProducts([id]);
          setStatusMsg({type: 'success', text: "تم حذف المنتج"});

          if (selectedIds.has(id)) {
              const newSet = new Set(selectedIds);
              newSet.delete(id);
              setSelectedIds(newSet);
          }

          refreshData();
      } catch (e: any) {
          console.error(e);
          const errorText = e.message || "خطأ غير معروف";
          setStatusMsg({type: 'error', text: `فشل الحذف (${errorText}). يرجى التحقق من إعدادات قاعدة البيانات.`});
      } finally {
          setIsDeleting(false);
      }
  };

  const handleSingleAdd = async () => {
    if(!newProductName) return;
    setIsSubmitting(true);
    clearStatus();
    try {
        await addProduct(newProductName, newProductPrice);
        setNewProductName('');
        setNewProductPrice('');
        setStatusMsg({type: 'success', text: "تمت إضافة المنتج بنجاح"});
        refreshData();
    } catch(e: any) {
        console.error(e);
        setStatusMsg({type: 'error', text: "خطأ: " + (e.message || "تأكد من الاتصال")});
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleBulkAdd = async () => {
    if (!bulkText.trim()) return;
    setIsSubmitting(true);
    clearStatus();

    const lines = bulkText.split('\n');
    const productsToAdd: {name: string, price: string | null}[] = [];

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;

        const match = trimmed.match(/^(.*)\s+([\d,.]+)$/);

        if (match) {
            const name = match[1].trim();
            const price = match[2];
            if (name) {
                productsToAdd.push({ name, price });
            }
        } else {
            productsToAdd.push({ name: trimmed, price: null });
        }
    }

    if (productsToAdd.length === 0) {
        setIsSubmitting(false);
        setStatusMsg({type: 'error', text: "لم يتم العثور على منتجات صالحة في النص"});
        return;
    }

    try {
        await addBatchProducts(productsToAdd);
        setBulkText(''); 
        setStatusMsg({type: 'success', text: `تم إضافة ${productsToAdd.length} منتج بنجاح`});
        refreshData();
    } catch (e: any) {
        console.error(e);
        setStatusMsg({type: 'error', text: "حدث خطأ أثناء الإضافة: " + (e.message || "خطأ في الشبكة أو قاعدة البيانات")});
    } finally {
        setIsSubmitting(false);
    }
  };

  const reviewedCount = products.filter(p => !p.is_review_requested && p.price !== null).length;
  const pendingCount = products.filter(p => p.is_review_requested).length;

  return (
    <div className="bg-slate-50 min-h-screen pb-20">
      <OrderSheet 
        isOpen={isOrderSheetOpen} 
        onClose={() => setIsOrderSheetOpen(false)} 
        cart={cart}
        setCart={setCart}
      />

      {/* Header */}
      <div className="bg-slate-800 text-white p-4 sticky top-0 z-20 shadow-lg">
        <div className="flex justify-between items-center mb-4">
            <h1 className="text-xl font-bold flex items-center gap-2">
                <span className="w-3 h-3 rounded-full bg-emerald-400"></span>
                لوحة التحكم
            </h1>
            <div className="flex gap-2">
                <button 
                  onClick={() => setIsOrderSheetOpen(true)} 
                  className="bg-slate-700 p-2 rounded-lg hover:bg-slate-600 relative"
                  title="سلة الطلبات"
                >
                    <ShoppingCart className="w-5 h-5 text-white" />
                    {cart.length > 0 && (
                        <span className="absolute -top-1 -right-1 bg-red-500 text-white w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold">
                            {cart.length}
                        </span>
                    )}
                </button>
                <button 
                  onClick={() => setShowSqlHelp(true)} 
                  className="bg-slate-700 p-2 rounded-lg hover:bg-slate-600 text-emerald-300"
                  title="إصلاح قاعدة البيانات"
                >
                    <Database className="w-5 h-5" />
                </button>
                <button onClick={onLogout} className="bg-slate-700 p-2 rounded-lg hover:bg-slate-600">
                    <LogOut className="w-5 h-5" />
                </button>
            </div>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-2">
            <div className="bg-slate-700/50 p-2 rounded text-center">
                <div className="text-2xl font-bold">{pendingCount}</div>
                <div className="text-xs text-slate-300">قيد المراجعة</div>
            </div>
             <div className="bg-slate-700/50 p-2 rounded text-center">
                <div className="text-2xl font-bold">{reviewedCount}</div>
                <div className="text-xs text-slate-300">مكتمل</div>
            </div>
        </div>

        <div className="flex gap-2 mt-4 text-sm">
            <button 
                onClick={() => { setActiveTab('manage'); clearStatus(); }}
                className={`flex-1 py-2 rounded-lg transition-colors flex items-center justify-center gap-2 ${activeTab === 'manage' ? 'bg-emerald-500 font-bold' : 'bg-slate-700'}`}
            >
                <FileText className="w-4 h-4" />
                إدارة الأسعار
            </button>
            <button 
                onClick={() => { setActiveTab('add'); clearStatus(); }}
                className={`flex-1 py-2 rounded-lg transition-colors flex items-center justify-center gap-2 ${activeTab === 'add' ? 'bg-emerald-500 font-bold' : 'bg-slate-700'}`}
            >
                <PackagePlus className="w-4 h-4" />
                إضافة سلع
            </button>
        </div>
      </div>

      {/* Status Message Banner */}
      {statusMsg && (
          <div className={`p-4 mx-4 mt-4 rounded-lg flex items-center gap-2 ${statusMsg.type === 'success' ? 'bg-green-100 text-green-800 border border-green-200' : 'bg-red-100 text-red-800 border border-red-200'}`}>
              {statusMsg.type === 'success' ? <CheckCircle className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}
              <span className="font-bold">{statusMsg.text}</span>
              <button onClick={clearStatus} className="mr-auto p-1 hover:bg-black/10 rounded"><X className="w-4 h-4"/></button>
          </div>
      )}

      {/* SQL Help Modal */}
      {showSqlHelp && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-white rounded-2xl shadow-2xl p-6 w-full max-w-lg">
             <div className="flex justify-between items-center mb-4 border-b pb-2">
               <h3 className="text-lg font-bold flex items-center gap-2">
                 <Database className="w-5 h-5 text-emerald-600"/>
                 إصلاح مشاكل قاعدة البيانات
               </h3>
               <button onClick={() => setShowSqlHelp(false)} className="text-gray-500 hover:text-black"><X/></button>
             </div>

             <p className="text-sm text-gray-600 mb-3">
               اذا واجهت مشاكل في <b>الحذف</b> أو <b>الإضافة</b>، قم بتشغيل الكود التالي في Supabase SQL Editor:
             </p>

             <div className="bg-slate-900 rounded-lg p-3 mb-4 relative">
                <pre className="text-emerald-400 font-mono text-xs overflow-x-auto whitespace-pre-wrap text-left dir-ltr max-h-60 overflow-y-auto">
                    {FIX_SQL.trim()}
                </pre>
                <button 
                  onClick={handleCopySQL}
                  className="absolute top-2 right-2 bg-white/10 hover:bg-white/20 text-white p-2 rounded transition-colors"
                  title="نسخ الكود"
                >
                    {copied ? <Check className="w-4 h-4 text-emerald-400" /> : <Copy className="w-4 h-4" />}
                </button>
             </div>

             <button onClick={() => setShowSqlHelp(false)} className="w-full bg-slate-100 text-slate-700 font-bold py-2 rounded-lg">
               إغلاق
             </button>
           </div>
        </div>
      )}

      {activeTab === 'manage' && (
          <div className="p-4">
             <div className="flex gap-2 mb-4">
                 <div className="relative flex-1">
                     <Search className="absolute right-3 top-3 text-gray-400 w-4 h-4" />
                     <input 
                        className="w-full pl-2 pr-9 py-2 rounded-lg border focus:ring-2 focus:ring-emerald-500"
                        placeholder="بحث سريع..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                     />
                 </div>
                 <button 
                    onClick={() => exportToExcel(products)}
                    className="bg-green-600 text-white p-2 rounded-lg shadow active:scale-95"
                    title="تنزيل Excel"
                 >
                     <Download className="w-6 h-6" />
                 </button>
             </div>

             {selectedIds.size > 0 && (
                 <div className="fixed bottom-0 left-0 right-0 bg-white border-t p-4 shadow-lg z-30 flex items-center justify-between animate-in slide-in-from-bottom">
                     <span className="font-bold text-slate-700">{selectedIds.size} عناصر محددة</span>
                     <div className="flex gap-2">
                        <button 
                            onClick={handleBulkDelete}
                            disabled={isDeleting || sending}
                            className="bg-red-100 text-red-600 px-4 py-2 rounded-lg font-bold shadow hover:bg-red-200 flex items-center gap-2"
                        >
                            {isDeleting ? '...' : <Trash2 className="w-5 h-5" />}
                        </button>
                        <button 
                            onClick={handleSendReview}
                            disabled={sending || isDeleting}
                            className="bg-orange-500 text-white px-6 py-2 rounded-lg font-bold shadow flex items-center gap-2"
                        >
                            {sending ? 'جاري الارسال...' : 'إرسال للمراجعة'}
                            <Send className="w-4 h-4" />
                        </button>
                     </div>
                 </div>
             )}

             <div className="bg-white rounded-lg shadow overflow-hidden">
                 <div className="p-3 border-b flex items-center gap-3 bg-gray-50">
                     <button onClick={selectAll}>
                         {selectedIds.size === filteredProducts.length && filteredProducts.length > 0 ? (
                             <CheckSquare className="w-6 h-6 text-emerald-600" />
                         ) : (
                             <Square className="w-6 h-6 text-gray-400" />
                         )}
                     </button>
                     <span className="font-bold text-gray-600">تحديد الكل</span>
                 </div>

                 <div className="divide-y max-h-[60vh] overflow-y-auto">
                     {filteredProducts.map(p => (
                         <div 
                            key={p.id} 
                            className={`flex items-center gap-3 p-3 ${selectedIds.has(p.id) ? 'bg-emerald-50' : 'hover:bg-gray-50'} cursor-pointer group`}
                            onClick={() => toggleSelect(p.id)}
                         >
                             {selectedIds.has(p.id) ? (
                                 <CheckSquare className="w-5 h-5 text-emerald-600 flex-shrink-0" />
                             ) : (
                                 <Square className="w-5 h-5 text-gray-300 flex-shrink-0" />
                             )}
                             <div className="flex-1">
                                 <div className="font-medium text-gray-800">{p.name}</div>
                                 <div className="text-sm text-gray-500">{p.price !== null ? `${Number(p.price).toLocaleString()} جنية` : 'غير مسعر'}</div>
                             </div>

                             <div className="flex items-center gap-2">
                                 {p.is_review_requested && (
                                     <span className="text-xs bg-orange-100 text-orange-600 px-2 py-1 rounded-full whitespace-nowrap">قيد المراجعة</span>
                                 )}

                                 {p.price !== null && (
                                     <button 
                                         onClick={(e) => addToCart(p, e)}
                                         className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-full transition-colors"
                                         title="إضافة للسلة"
                                     >
                                         <Plus className="w-5 h-5" />
                                     </button>
                                 )}

                                 <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleSingleDelete(p.id);
                                    }}
                                    className="p-2 text-red-300 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors opacity-100 sm:opacity-0 sm:group-hover:opacity-100"
                                    title="حذف"
                                 >
                                     <Trash2 className="w-5 h-5" />
                                 </button>
                             </div>
                         </div>
                     ))}
                 </div>
             </div>
          </div>
      )}

      {activeTab === 'add' && (
          <div className="p-4 sm:p-6">
              <div className="bg-white rounded-xl shadow p-4 sm:p-6">
                  <div className="flex p-1 bg-slate-100 rounded-lg mb-6">
                      <button 
                        onClick={() => { setAddMode('single'); clearStatus(); }}
                        className={`flex-1 py-2 text-sm font-bold rounded-md transition-all ${addMode === 'single' ? 'bg-white shadow text-emerald-600' : 'text-slate-500 hover:text-slate-700'}`}
                      >
                          منتج واحد
                      </button>
                      <button 
                        onClick={() => { setAddMode('bulk'); clearStatus(); }}
                        className={`flex-1 py-2 text-sm font-bold rounded-md transition-all ${addMode === 'bulk' ? 'bg-white shadow text-emerald-600' : 'text-slate-500 hover:text-slate-700'}`}
                      >
                          قائمة سريعة (Bulk)
                      </button>
                  </div>

                  {addMode === 'single' ? (
                      <div className="space-y-4 animate-in fade-in duration-300">
                          <div className="flex justify-center mb-4">
                              <div className="bg-emerald-100 p-4 rounded-full">
                                  <PackagePlus className="w-8 h-8 text-emerald-600" />
                              </div>
                          </div>
                          <div>
                              <label className="block font-bold text-slate-700 mb-2">اسم المنتج الجديد</label>
                              <input 
                                className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                                value={newProductName}
                                onChange={e => setNewProductName(e.target.value)}
                                placeholder="مثال: شاي الغزالتين"
                              />
                          </div>
                          <div>
                              <label className="block font-bold text-slate-700 mb-2">السعر المبدئي</label>
                              <input 
                                type="number"
                                className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                                value={newProductPrice}
                                onChange={e => setNewProductPrice(e.target.value)}
                                placeholder="0"
                              />
                          </div>
                          <button 
                            onClick={handleSingleAdd}
                            disabled={isSubmitting}
                            className="w-full bg-slate-800 text-white py-3 rounded-lg font-bold mt-4 disabled:opacity-50 flex items-center justify-center gap-2"
                          >
                              {isSubmitting ? (
                                  <>جاري الإضافة...</>
                              ) : (
                                  <>إضافة للقائمة <PackagePlus className="w-4 h-4"/></>
                              )}
                          </button>
                      </div>
                  ) : (
                      <div className="space-y-4 animate-in fade-in duration-300">
                          <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 text-sm text-blue-800 mb-2">
                              <p className="font-bold flex items-center gap-2"><ListPlus className="w-4 h-4"/> تعليمات:</p>
                              <p>انسخ القائمة والصقها هنا. النظام سيفصل السعر تلقائياً إذا كان في نهاية السطر ومسبوقاً بمسافة.</p>
                              <p className="mt-1 text-xs opacity-75 dir-ltr text-right font-mono">"سكر 10 كيلو 31000"</p>
                          </div>

                          <textarea 
                            className="w-full h-64 p-3 border rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none font-mono text-sm leading-relaxed"
                            value={bulkText}
                            onChange={e => setBulkText(e.target.value)}
                            placeholder={`مثال:\nسكر 10 كيلو 31000\nزيت صباح 1 لتر 8000\nعدسية ملوة`}
                          />

                          <button 
                            onClick={handleBulkAdd}
                            disabled={isSubmitting}
                            className="w-full bg-slate-800 text-white py-3 rounded-lg font-bold mt-2 disabled:opacity-50 flex items-center justify-center gap-2"
                          >
                               {isSubmitting ? (
                                  <>جاري المعالجة...</>
                              ) : (
                                  <>إضافة القائمة كاملة <ListPlus className="w-4 h-4"/></>
                              )}
                          </button>
                      </div>
                  )}
              </div>
          </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { Product, CartItem, Order } from '../types';
import { ShoppingCart, Plus, Minus, Trash2, Save, Copy, X, History, ChevronDown, Check, Edit2, Truck, Percent } from 'lucide-react';
import { saveOrder, fetchOrders, deleteOrder, updateOrder } from '../services/productService';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  setCart: React.Dispatch<React.SetStateAction<CartItem[]>>;
}

const OrderSheet: React.FC<Props> = ({ isOpen, onClose, cart, setCart }) => {
  const [activeTab, setActiveTab] = useState<'current' | 'history'>('current');
  const [globalProfitMargin, setGlobalProfitMargin] = useState(0); // Percentage
  const [deliveryCost, setDeliveryCost] = useState<string>(''); // Kept as string for input handling
  const [savedOrders, setSavedOrders] = useState<Order[]>([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const [currentOrderId, setCurrentOrderId] = useState<string | null>(null); // If editing an existing order
  const [orderName, setOrderName] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  // Load history when tab changes
  useEffect(() => {
    if (activeTab === 'history') {
        setIsLoadingHistory(true);
        fetchOrders()
            .then(setSavedOrders)
            .catch(console.error)
            .finally(() => setIsLoadingHistory(false));
    }
  }, [activeTab]);

  const updateQuantity = (productId: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.productId === productId) {
              const newQty = Math.max(1, item.quantity + delta);
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const updateItemProfit = (productId: string, profit: number) => {
      setCart(prev => prev.map(item => {
          if (item.productId === productId) {
              return { ...item, itemProfit: profit };
          }
          return item;
      }));
  };

  const removeItem = (productId: string) => {
      setCart(prev => prev.filter(i => i.productId !== productId));
  };

  // Calculations
  const totals = useMemo(() => {
      let subTotal = 0;

      cart.forEach(item => {
          // Use item specific profit if set, otherwise global
          const margin = item.itemProfit !== undefined ? item.itemProfit : globalProfitMargin;
          const unitPriceWithProfit = item.originalPrice * (1 + margin / 100);
          subTotal += unitPriceWithProfit * item.quantity;
      });

      const delivery = Number(deliveryCost) || 0;
      const grandTotal = subTotal + delivery;

      return { subTotal, delivery, grandTotal };
  }, [cart, globalProfitMargin, deliveryCost]);

  const generateReceiptText = () => {
    // Determine Order Name/ID
    const title = orderName || 'بدون رقم';

    let text = `✅ تم استلام طلبك\n`;
    text += `رقم الطلب: ${title}\n\n`;
    text += `المنتجات:\n`;

    cart.forEach((item) => {
        const margin = item.itemProfit !== undefined ? item.itemProfit : globalProfitMargin;
        const unitPriceWithProfit = item.originalPrice * (1 + margin / 100);
        const itemTotal = unitPriceWithProfit * item.quantity;

        text += `${item.name} × ${item.quantity} = ${Math.round(itemTotal).toLocaleString()}\n`;
    });

    text += `\n💰 الإجمالي: ${Math.round(totals.subTotal).toLocaleString()} جنيه\n`;

    if (totals.delivery > 0) {
        text += `🚚 التوصيل: ${Math.round(totals.delivery).toLocaleString()} جنيه\n`;
    }

    text += `الاجمالي الكلي: ${Math.round(totals.grandTotal).toLocaleString()} جنية\n`;
    text += `📦 التسليم اليوم مساءً إن شاء الله\n\n`;
    text += `شكرًا لثقتك 🌸`;
    return text;
  };

  const handleCopy = () => {
      const text = generateReceiptText();
      navigator.clipboard.writeText(text);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleSave = async () => {
      if (cart.length === 0) return;

      const name = orderName || `طلب ${new Date().toLocaleDateString('ar-EG')} - ${new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'})}`;

      try {
          const orderData = {
              name,
              items: cart,
              profit_margin: globalProfitMargin,
              delivery_cost: Number(deliveryCost) || 0,
              total_price: totals.grandTotal
          };

          if (currentOrderId) {
              await updateOrder(currentOrderId, orderData);
              alert("تم تحديث الطلب بنجاح");
          } else {
              await saveOrder(orderData);
              alert("تم حفظ الطلب الجديد");
          }

          setOrderName('');
          setDeliveryCost('');
          setCurrentOrderId(null);
          setCart([]);
          onClose();
      } catch (e: any) {
          console.error(e);
          alert("فشل الحفظ: " + (e.message || "خطأ غير معروف. تأكد من تحديث قاعدة البيانات من زر الإصلاح في لوحة التحكم."));
      }
  };

  const loadOrderToCart = (order: Order) => {
      setCart(order.items);
      setGlobalProfitMargin(Number(order.profit_margin) || 0);
      setDeliveryCost(order.delivery_cost?.toString() || '');
      setOrderName(order.name);
      setCurrentOrderId(order.id);
      setActiveTab('current');
  };

  const handleDeleteOrder = async (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      if(!window.confirm("حذف هذا السجل؟")) return;
      try {
          await deleteOrder(id);
          setSavedOrders(prev => prev.filter(o => o.id !== id));
      } catch (e) {
          alert("فشل الحذف");
      }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/30 backdrop-blur-sm" onClick={onClose} />

      {/* Sliding Panel */}
      <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">

        {/* Header */}
        <div className="p-4 bg-slate-800 text-white flex justify-between items-center shadow-md z-10">
            <h2 className="text-xl font-bold flex items-center gap-2">
                <ShoppingCart className="w-6 h-6 text-emerald-400" />
                إدارة الطلبات (Admin)
            </h2>
            <button onClick={onClose} className="p-2 hover:bg-slate-700 rounded-full">
                <X className="w-6 h-6" />
            </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b">
            <button 
                onClick={() => setActiveTab('current')}
                className={`flex-1 py-3 font-bold text-sm flex items-center justify-center gap-2 transition-colors ${activeTab === 'current' ? 'text-emerald-600 border-b-2 border-emerald-600 bg-emerald-50' : 'text-gray-500'}`}
            >
                <Edit2 className="w-4 h-4" />
                الطلب الحالي ({cart.length})
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`flex-1 py-3 font-bold text-sm flex items-center justify-center gap-2 transition-colors ${activeTab === 'history' ? 'text-emerald-600 border-b-2 border-emerald-600 bg-emerald-50' : 'text-gray-500'}`}
            >
                <History className="w-4 h-4" />
                السجل المحفوظ
            </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto bg-gray-50 p-4">
            {activeTab === 'current' && (
                <>
                    {cart.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-gray-400">
                            <ShoppingCart className="w-16 h-16 mb-4 opacity-20" />
                            <p>السلة فارغة</p>
                            <p className="text-sm">أضف منتجات من القائمة الرئيسية</p>
                        </div>
                    ) : (
                        <div className="space-y-4 pb-20">
                            {/* Order Name */}
                            <input 
                                className="w-full p-2 border rounded-lg mb-2 text-sm"
                                placeholder="اسم الطلب / رقم الطلب"
                                value={orderName}
                                onChange={e => setOrderName(e.target.value)}
                            />

                            {/* Items List */}
                            <div className="space-y-3">
                                {cart.map(item => {
                                    const itemMargin = item.itemProfit !== undefined ? item.itemProfit : globalProfitMargin;
                                    const effectivePrice = item.originalPrice * (1 + itemMargin / 100);

                                    return (
                                        <div key={item.productId} className="bg-white p-3 rounded-lg shadow-sm border border-gray-200">
                                            <div className="flex justify-between items-start mb-2">
                                                <span className="font-bold text-gray-800">{item.name}</span>
                                                <button onClick={() => removeItem(item.productId)} className="text-red-400 hover:text-red-600">
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            </div>

                                            <div className="flex justify-between items-center mb-2">
                                                <div className="text-sm text-gray-500">
                                                    الأساسي: {item.originalPrice.toLocaleString()}
                                                </div>
                                                <div className="flex items-center gap-1 text-xs bg-slate-100 px-2 py-1 rounded">
                                                     <Percent className="w-3 h-3 text-slate-500"/>
                                                     <input 
                                                        type="number"
                                                        className="w-8 bg-transparent text-center border-b border-slate-300 focus:border-emerald-500 outline-none"
                                                        value={item.itemProfit !== undefined ? item.itemProfit : ''}
                                                        placeholder={globalProfitMargin.toString()}
                                                        onChange={(e) => updateItemProfit(item.productId, Number(e.target.value))}
                                                     />
                                                     <span>%</span>
                                                </div>
                                            </div>

                                            <div className="flex justify-between items-center border-t pt-2">
                                                <div className="font-bold text-emerald-700">
                                                    {Math.round(effectivePrice * item.quantity).toLocaleString()} جنية
                                                </div>
                                                <div className="flex items-center gap-3 bg-gray-100 rounded-lg px-2 py-1">
                                                    <button onClick={() => updateQuantity(item.productId, -1)} className="p-1 hover:bg-white rounded shadow-sm"><Minus className="w-3 h-3"/></button>
                                                    <span className="font-bold w-4 text-center">{item.quantity}</span>
                                                    <button onClick={() => updateQuantity(item.productId, 1)} className="p-1 hover:bg-white rounded shadow-sm"><Plus className="w-3 h-3"/></button>
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Global Settings */}
                            <div className="bg-white p-4 rounded-lg shadow-sm mt-4 border border-slate-200 space-y-4">
                                <div>
                                    <label className="block text-sm font-bold text-gray-700 mb-2">نسبة الربح العامة (%)</label>
                                    <div className="flex gap-4 items-center">
                                        <input 
                                            type="range" min="0" max="100" step="1"
                                            value={globalProfitMargin}
                                            onChange={e => setGlobalProfitMargin(Number(e.target.value))}
                                            className="flex-1 accent-emerald-600"
                                        />
                                        <span className="bg-emerald-100 text-emerald-800 px-3 py-1 rounded-lg font-bold min-w-[3rem] text-center">
                                            {globalProfitMargin}%
                                        </span>
                                    </div>
                                    <p className="text-xs text-gray-400 mt-1">يتم تطبيقها على المنتجات التي لم تحدد لها نسبة خاصة</p>
                                </div>

                                <div className="border-t pt-3">
                                     <label className="block text-sm font-bold text-gray-700 mb-2 flex items-center gap-2">
                                        <Truck className="w-4 h-4"/>
                                        تكلفة التوصيل
                                     </label>
                                     <input 
                                        type="number"
                                        className="w-full p-2 border rounded-lg"
                                        placeholder="0"
                                        value={deliveryCost}
                                        onChange={e => setDeliveryCost(e.target.value)}
                                     />
                                </div>
                            </div>
                        </div>
                    )}
                </>
            )}

            {activeTab === 'history' && (
                <div className="space-y-3">
                    {isLoadingHistory ? (
                        <p className="text-center text-gray-500 mt-10">جاري التحميل...</p>
                    ) : savedOrders.length === 0 ? (
                        <p className="text-center text-gray-400 mt-10">لا توجد طلبات محفوظة</p>
                    ) : (
                        savedOrders.map(order => (
                            <div key={order.id} onClick={() => loadOrderToCart(order)} className="bg-white p-3 rounded-lg shadow-sm border hover:border-emerald-400 cursor-pointer transition-colors group relative">
                                <div className="font-bold text-gray-800 mb-1">{order.name || 'بدون اسم'}</div>
                                <div className="text-xs text-gray-500 mb-2">
                                    {new Date(order.created_at).toLocaleDateString('ar-EG')} • {order.items.length} منتج
                                </div>
                                <div className="flex justify-between items-center">
                                    <div className="font-bold text-emerald-600">
                                        {Number(order.total_price).toLocaleString()} جنية
                                    </div>
