import { Product } from "../types";
import { fetchFullPriceHistory } from "../services/productService";

export const exportToExcel = async (products: Product[]) => {
  if (!window.XLSX) {
    alert("Excel library not loaded. Please refresh.");
    return;
  }

  // 1. Fetch History Data
  let historyData: any[] = [];
  try {
      historyData = await fetchFullPriceHistory();
  } catch (e) {
      console.log("History export skipped or failed");
  }

  // 2. Process History into a Matrix (Pivot Table)
  // Get all unique dates from history, sorted
  const uniqueDates = Array.from(new Set(historyData.map(h => h.recorded_date))).sort();

  // Map Product ID to an object of { date: price }
  const historyMap: Record<string, Record<string, number>> = {};
  historyData.forEach(h => {
      if (!historyMap[h.product_id]) historyMap[h.product_id] = {};
      historyMap[h.product_id][h.recorded_date] = h.price;
  });

  // 3. Construct the Export Data Row by Row
  const data = products.map(p => {
    const row: any = {
      "ProductName | اسم_المنتج": p.name,
      "CurrentPrice | السعر_الحالي": p.price
    };

    // Add columns dynamically for each date
    uniqueDates.forEach(date => {
        const priceAtDate = historyMap[p.id]?.[date];
        row[`${date}`] = priceAtDate !== undefined ? priceAtDate : ''; // Empty string if no price that day
    });

    return row;
  });

  const worksheet = window.XLSX.utils.json_to_sheet(data);
  const workbook = window.XLSX.utils.book_new();

  // Adjust column width
  const wscols = [
    { wch: 40 }, // Width for Name
    { wch: 20 }, // Width for Current Price
    ...uniqueDates.map(() => ({ wch: 15 })) // Width for date columns
  ];
  worksheet['!cols'] = wscols;

  window.XLSX.utils.book_append_sheet(workbook, worksheet, "الأسعار_والسجل");

  const date = new Date().toISOString().slice(0, 10);
  window.XLSX.writeFile(workbook, `نسخة_احتياطية_ذكية_${date}.xlsx`);
};

